def insert(root, key):
    if root is None:
        return Node(key)
    else:
        if key < root.val:
            root.left = insert(root.left, key)
        else:
            root.right = insert(root.right, key)
    return root

def store_sorted(root, arr, index):
    if root is not None:
        index = store_sorted(root.left, arr, index)
        arr[index] = root.val
        index += 1
        index = store_sorted(root.right, arr, index)
    return index

