class TreeSort {
    private class Node {
        var key: Int
        var left: Node?
        var right: Node?

        init(_ key: Int) {
            self.key = key
            self.left = nil
            self.right = nil
        }
    }

    static func sort(_ arr: inout [Int]) {
        var root: Node? = nil
        for value in arr {
            root = insert(root, value)
        }

        var index = 0
        storeSorted(root, &arr, &index)
    }

    private static func insert(_ root: Node?, _ key: Int) -> Node {
        guard let root = root else {
            return Node(key)
        }

        if key < root.key {
            root.left = insert(root.left, key)
        } else {
            root.right = insert(root.right, key)
        }

        return root
    }

    private static func storeSorted(_ root: Node?, _ arr: inout [Int], _ index: inout Int) {
        if let root = root {
            storeSorted(root.left, &arr, &index)
            arr[index] = root.key
            index += 1
            storeSorted(root.right, &arr, &index)
        }
    }
}

class Node {
  key: number;
  left: Node | null;
  right: Node | null;

  constructor(key: number) {
    this.key = key;
    this.left = null;
    this.right = null;
  }
}

export function treeSort(arr: number[]): number[] {
  let root: Node | null = null;
  for (const value of arr) {
    root = insert(root, value);
  }

  let index = 0;
  storeSorted(root, arr, { get: () => index, inc: () => index++ });
  return arr;
}

function insert(root: Node | null, key: number): Node {
  if (root === null) {
    return new Node(key);
  }

  if (key < root.key) {
    root.left = insert(root.left, key);
  } else {
    root.right = insert(root.right, key);
  }

  return root;
}

function storeSorted(root: Node | null, arr: number[], idx: { get: () => number, inc: () => number }): void {
  if (root !== null) {
    storeSorted(root.left, arr, idx);
    arr[idx.inc()] = root.key;
    storeSorted(root.right, arr, idx);
  }
}

class BSTNode {
    val: number;
    left: BSTNode | null = null;
    right: BSTNode | null = null;

    constructor(val: number) {
        this.val = val;
    }
}

function insertBST(root: BSTNode | null, val: number): BSTNode {
    if (root === null) return new BSTNode(val);
    if (val < root.val) root.left = insertBST(root.left, val);
    else root.right = insertBST(root.right, val);
    return root;
}

function inorderBST(root: BSTNode | null, result: number[]): void {
    if (root !== null) {
        inorderBST(root.left, result);
        result.push(root.val);
        inorderBST(root.right, result);
    }
}

export function treeSort(arr: number[]): number[] {
    if (arr.length <= 1) return [...arr];

    let root: BSTNode | null = null;
    for (const val of arr) {
        root = insertBST(root, val);
    }

    const result: number[] = [];
    inorderBST(root, result);
    return result;
}
